mapper.select:
SELECT t.teaching_id, c.id AS course_id, c.course_name, te.teacher_name, cr.room_name AS classroom_name, ts.weekday, ts.section, TIME_FORMAT(ts.start_time, '%H:%i') AS start_time, TIME_FORMAT(ts.end_time, '%H:%i') AS end_time, c.credit, c.hours, t.semester FROM enrollment e INNER JOIN teaching t ON e.teaching_id = t.teaching_id INNER JOIN course c ON t.course_id = c.id INNER JOIN teacher te ON t.teacher_id = te.teacher_id INNER JOIN classroom cr ON t.room_id = cr.room_id INNER JOIN time_schedule ts ON t.schedule_id = ts.schedule_id WHERE e.student_id = #{studentId}
AND t.semester = #{semester}
ORDER BY ts.weekday, ts.start_time

SELECT COUNT(*)
FROM enrollment
WHERE student_id = #{studentId} AND teaching_id = #{teachingId}

SELECT ts.*
FROM enrollment e
         INNER JOIN teaching t ON e.teaching_id = t.teaching_id
         INNER JOIN time_schedule ts ON t.schedule_id = ts.schedule_id
WHERE e.student_id = #{studentId}
  AND t.semester = #{semester}

SELECT t.teaching_id, c.course_name, te.teacher_name, c.credit, c.hours, ts.weekday, ts.section, cr.room_name AS classroom, t.semester, e.grade FROM enrollment e INNER JOIN teaching t ON e.teaching_id = t.teaching_id INNER JOIN course c ON t.course_id = c.id INNER JOIN teacher te ON t.teacher_id = te.teacher_id INNER JOIN time_schedule ts ON t.schedule_id = ts.schedule_id INNER JOIN classroom cr ON t.room_id = cr.room_id WHERE e.student_id = #{studentId}
AND t.semester = #{semester}
ORDER BY ts.weekday, ts.start_time
